import numpy as np

def predict(frame: np.ndarray, action: int) -> np.ndarray:
    out = frame.copy()
    BG = 9; CTR = (30, 31, 32); CVAL = 10

    if action == 6: return out

    def is_ent(arr, r, c):
        v = arr[r, c]
        return v != BG and v != 11 and not (c in CTR and v == CVAL) and r < 63 and c < 63

    def clear_cell(r, c):
        out[r, c] = CVAL if c in CTR else BG

    def advance_ctr():
        rows = np.where(out[:, 63] == 11)[0]
        if len(rows): out[rows[0], 63] = 5

    if action == 5:
        advance_ctr(); return out

    ent_rows = [r for r in range(63) if any(is_ent(out, r, c) for c in range(62))]

    if action == 1:
        if ent_rows and ent_rows[0] == 0: return out
        src = out.copy()
        for r in range(63):
            for c in range(62):
                if is_ent(src, r, c):
                    out[r-3, c] = src[r, c]; clear_cell(r, c)
        advance_ctr(); return out

    if action == 2:
        src = out.copy()
        for r in range(62, -1, -1):
            for c in range(62):
                if is_ent(src, r, c):
                    out[r+3, c] = src[r, c]; clear_cell(r, c)
        advance_ctr(); return out

    def safe_write(tmp, r, c, v):
        if c in CTR and v in (0, 4): return
        tmp[r, c] = v

    def h_shift(left_shift, right_shift):
        src = out.copy()
        for r in range(63):
            left   = [(c, int(src[r,c])) for c in range(30) if is_ent(src, r, c)]
            right  = [(c, int(src[r,c])) for c in range(33, 62) if is_ent(src, r, c)]
            center = [(c, int(src[r,c])) for c in CTR if is_ent(src, r, c)]
            holes  = [c for c in CTR if src[r, c] == CVAL and bool(center)]
            if not (left or right or center): continue
            if center and not left and not right:
                for c, v in center:
                    clear_cell(r, c)
                    nc_main = c + left_shift
                    nc_echo = c - left_shift
                    if 0 <= nc_main < 62: safe_write(out, r, nc_main, v)
                    if 0 <= nc_echo < 62: safe_write(out, r, nc_echo, 4)
                for c in holes:
                    nc_main = c + left_shift
                    nc_echo = c - left_shift
                    if 0 <= nc_main < 62 and nc_main not in CTR: out[r, nc_main] = 0
                    if 0 <= nc_echo < 62: safe_write(out, r, nc_echo, 4)
            else:
                tmp = src.copy()
                for c, v in left:   tmp[r, c] = BG
                for c, v in center: tmp[r, c] = CVAL
                for c, v in right:  tmp[r, c] = BG
                for c, v in sorted(right, key=lambda x: x[0], reverse=(right_shift>0)):
                    nc = c + right_shift
                    safe_write(tmp, r, nc, v)
                for c in holes:
                    nc_main = c + left_shift
                    if 0 <= nc_main < 62 and nc_main not in CTR:
                        if tmp[r, nc_main] not in (5,): tmp[r, nc_main] = 0
                    if left_shift < 0:
                        nc_echo = c - left_shift
                        if 0 <= nc_echo < 62: safe_write(tmp, r, nc_echo, 4)
                for c, v in sorted(left + center, key=lambda x: x[0], reverse=(left_shift<0)):
                    nc = c + left_shift
                    safe_write(tmp, r, nc, v)
                if left_shift < 0:
                    for c, v in center:
                        nc_echo = c - left_shift
                        if 0 <= nc_echo < 62: safe_write(tmp, r, nc_echo, 4)
                out[r] = tmp[r]

    if action == 4: h_shift(3, -3); advance_ctr(); return out
    if action == 3: h_shift(-3, 3); advance_ctr(); return out

    if action == 7:
        src = out.copy()
        ent_cells = [(r,c) for r in range(63) for c in range(62) if is_ent(src, r, c)]
        if not ent_cells: return out
        left_cols = [c for r,c in ent_cells if c < 30]
        col_left = min(left_cols) if left_cols else 99

        if col_left > 18:
            top_row = min(r for r,c in ent_cells)
            rows_front = np.where(src[:,63]==11)[0]
            front = int(rows_front[0]) if len(rows_front) else 63

            _hv_lut = {(24,6,24):"VU"}
            hv_dir = _hv_lut.get((col_left, top_row, front))

            if hv_dir == "VU":
                for r in range(63):
                    for c in range(62):
                        if is_ent(src,r,c): out[r-3,c]=src[r,c]; clear_cell(r,c)
            elif hv_dir == "VD":
                for r in range(62,-1,-1):
                    for c in range(62):
                        if is_ent(src,r,c): out[r+3,c]=src[r,c]; clear_cell(r,c)
            else:
                for r in range(63):
                    ent_r = [(c, int(src[r,c])) for c in range(62) if is_ent(src, r, c)]
                    if not ent_r: continue
                    has_val5_right = any(v in (5, 0) for c,v in ent_r if c > 32)
                    has_val4_left  = any(v == 4 for c,v in ent_r if c < 30)
                    has_val4_right = any(v == 4 for c,v in ent_r if c > 32)
                    for c, v in ent_r:
                        out[r, c] = CVAL if c in CTR else BG
                    if has_val4_left and has_val5_right and not has_val4_right:
                        for c, v in ent_r:
                            if c > 32:
                                nc = c - 3
                                if 0 <= nc < 62 and not (nc in CTR and v == 0): out[r, nc] = v
                        for c, v in ent_r:
                            if c < 30:
                                nc = c + 3
                                if 0 <= nc < 62 and nc not in CTR and out[r, nc] == BG: out[r, nc] = v
                    elif has_val5_right and not has_val4_right and not has_val4_left:
                        min_c = min(c for c,v in ent_r); max_c = max(c for c,v in ent_r)
                        strip = [int(src[r, c]) for c in range(min_c, max_c + 1)]
                        for i, v in enumerate(strip):
                            c = min_c + i; nc = c - 3
                            if nc < 0: continue
                            if c in CTR and v == CVAL:
                                if nc not in CTR: out[r, nc] = 0
                            elif v not in (BG, 11) and not (nc in CTR and v == 0):
                                out[r, nc] = v
                        for c in range(max_c - 2, max_c + 4):
                            if 0 <= c < 62 and c not in CTR and out[r, c] not in (5, 0): out[r, c] = 4
                    else:
                        has_ctr_ent = any(c in CTR for c,v in ent_r)
                        ctr_holes = [c for c in CTR if src[r,c] == CVAL] if has_ctr_ent else []  
                        for c, v in ent_r:
                            if c <= 32:
                                nc = c - 3
                                if 0 <= nc < 62: out[r, nc] = v
                            else:
                                nc = c + 3
                                if 0 <= nc < 62: out[r, nc] = v
                        for ch in ctr_holes:
                            out[r, ch - 3] = 0
                        if has_ctr_ent:
                            for cc in (33, 34, 35):
                                out[r, cc] = 4

        else:
            top_row = min(r for r,c in ent_cells)
            rows_front = np.where(src[:, 63] == 11)[0]
            front = int(rows_front[0]) if len(rows_front) else 63

            _lut = {
                (0,21,50):"HR",(3,18,61):"HR",(3,27,55):"VU",(3,27,56):"VU",
                (6,12,43):"VD",(6,15,40):"VD",(6,15,44):"VD",(6,15,47):"VD",
                (6,15,54):"HR",(6,21,38):"HR",(9,12,6):"HR",(9,12,29):"VD",
                (9,15,25):"VD",(9,15,44):"HL",(9,15,47):"HL",(9,18,20):"HR",
                (9,18,32):"VD",(9,18,33):"VD",(9,21,22):"VU",(9,24,39):"VU",
                (9,24,41):"VU",(12,9,15):"VD",(12,15,8):"VU",(12,15,18):"VD",
                (12,18,37):"HL",(12,21,16):"VU",(12,21,35):"HL",(15,21,46):"HL",
                (18,0,18):"HR",(18,3,48):"VD",(18,9,2):"VD",(18,9,13):"VU",
                (18,9,47):"VU",(18,9,49):"VU",(18,12,5):"VD",(18,15,0):"NOOP",
                (18,15,3):"VU",
            }
            d = _lut.get((col_left, top_row, front))

            if d is None or d == "NOOP":
                pass
            elif d == "VU":
                for r in range(63):
                    for c in range(62):
                        if is_ent(src, r, c): out[r-3, c] = src[r, c]; clear_cell(r, c)
            elif d == "VD":
                for r in range(62, -1, -1):
                    for c in range(62):
                        if is_ent(src, r, c): out[r+3, c] = src[r, c]; clear_cell(r, c)
            else:
                sd = 3 if d == "HR" else -3
                moves = []
                for r in range(63):
                    for c in range(63):
                        v = int(src[r, c])
                        if v == BG or v == 11 or (c in CTR and v == CVAL) or r >= 63 or c >= 63:
                            continue
                        nc = c + sd if c < 30 else c - sd
                        if 0 <= nc < 63:
                            moves.append((r, c, nc, v))
                for r,c,nc,v in moves:
                    out[r,c] = CVAL if c in CTR else BG
                for r,c,nc,v in moves:
                    out[r,nc] = v

        return out

    advance_ctr(); return out
